{
  "summary": "The project will be updated to bundle all project data (JSON, PDF, and images) into a ZIP file upon export. The import process will be enhanced to support both ZIP files and directory uploads, allowing assets to be resolved from relative paths as requested.",
  "plan": [
    {
      "step": 1,
      "title": "Add ZIP library",
      "description": "Add `jszip` and its type definitions to `package.json` to enable bundle creation and extraction in the browser.",
      "files_affected": [
        "package.json"
      ],
      "type": "MODIFY"
    },
    {
      "step": 2,
      "title": "Update Export Logic",
      "description": "Modify `useExport.ts` to generate a ZIP file. The ZIP will contain `project.json`, the source PDF file, and an `assets/` folder for images and custom icons. Update the JSON structure to use relative paths for these assets instead of embedding large Base64 strings.",
      "files_affected": [
        "client/src/hooks/useExport.ts"
      ],
      "type": "MODIFY"
    },
    {
      "step": 3,
      "title": "Update Import Interface",
      "description": "Enhance `PDFUploader.tsx` to handle `.zip` files and directory selections (`webkitdirectory`). Implement logic to resolve asset paths from the uploaded bundle or directory and convert them back to usable URLs (Data/Blob) for the editor state.",
      "files_affected": [
        "client/src/components/editor/PDFUploader.tsx"
      ],
      "type": "MODIFY"
    },
    {
      "step": 4,
      "title": "Maintain Backward Compatibility",
      "description": "Ensure the `IMPORT_PROJECT` reducer action and the import logic in `PDFUploader.tsx` still support legacy standalone `.json` files containing embedded Base64 assets.",
      "files_affected": [
        "client/src/lib/editor-context.tsx",
        "client/src/components/editor/PDFUploader.tsx"
      ],
      "type": "MODIFY"
    }
  ],
  "acceptance_criteria": [
    {
      "id": "c1",
      "description": "Exporting a project generates a `.zip` file containing `project.json`, `document.pdf`, and an `assets/` directory.",
      "how_to_verify": "Trigger export in the UI and inspect the downloaded ZIP file structure."
    },
    {
      "id": "c2",
      "description": "`project.json` inside the ZIP uses relative paths (e.g., 'assets/image_1.png') for image content instead of Base64.",
      "how_to_verify": "Extract the ZIP and check the `content` fields in the `project.json` file."
    },
    {
      "id": "c3",
      "description": "Importing the generated ZIP file restores the full project state including the PDF and all visual objects.",
      "how_to_verify": "Upload a previously exported ZIP via the 'Import' tool and verify layers, icons, and images appear correctly."
    },
    {
      "id": "c4",
      "description": "Importing a folder (directory upload) containing the extracted ZIP content correctly resolves assets.",
      "how_to_verify": "Use the directory upload option, select an unzipped project folder, and verify all assets load correctly."
    },
    {
      "id": "c5",
      "description": "Legacy `.json` files with embedded Base64 data can still be imported.",
      "how_to_verify": "Import an old `project.json` file and verify it loads without errors."
    },
    {
      "id": "c6",
      "description": "The PDF file is automatically loaded into the viewer when a ZIP project is imported.",
      "how_to_verify": "Import a ZIP and ensure the canvas displays the correct PDF document immediately."
    }
  ],
  "risks": [
    "High memory consumption when Zipping very large PDF files or many high-resolution images.",
    "Dependency on `jszip` which must be compatible with the current build environment.",
    "Directory upload (`webkitdirectory`) is not supported in all browsers (e.g., older versions or specific mobile browsers)."
  ]
}

